+   * POST /download with {"path": "data/file.bin"}
+   * Returns raw binary with Content-Type: application/octet-stream.
+   */
+  private async handleDownload(body: any): Promise<Response> {
+    const { path } = body;
+    const data = await this.readR2File(path);
+    if (data === null) {
