+// ---- Helpers ----
+
+function parseCommand(cmd: string): string[] {
+  const parts: string[] = [];
+  let current = "";
+  let inSingle = false;
+  let inDouble = false;
+  let escape = false;
+
+  for (const ch of cmd) {
+    if (escape) {
+      current += ch;
+      escape = false;
+      continue;
+    }
+    if (ch === "\\") {
+      escape = true;
+      continue;
+    }
+    if (ch === "'" && !inDouble) {
+      inSingle = !inSingle;
+      continue;
+    }
+    if (ch === '"' && !inSingle) {
+      inDouble = !inDouble;
+      continue;
+    }
+    if (ch === " " && !inSingle && !inDouble) {
+      if (current) {
+        parts.push(current);
+        current = "";
+      }
+      continue;
+    }
+    current += ch;
+  }
+  if (current) parts.push(current);
+  return parts;
+}
+
+function resolvePath(target: string, cwd: string): string {
+  if (target.startsWith("/")) return target;
+  return (cwd + "/" + target).replace(/\/+/g, "/");
+}
+
+function escapeForPython(s: string): string {
+  return s.replace(/\\/g, "\\\\").replace(/"""/g, '\\"\\"\\"');
+}

